#include <stdio.h>
#include <math.h>

void fourierTransform(int **img, int rows, int cols) {
  int i, j, u, v;
  double real, imag;
  double pi = 3.14159265358979323846;

  for (i = 0; i < rows; i++) {
    for (j = 0; j < cols; j++) {
      real = 0.0;
      imag = 0.0;
      for (u = 0; u < rows; u++) {
        for (v = 0; v < cols; v++) {
          real += img[u][v] * cos(2 * pi * (u * i / rows + v * j / cols));
          imag += img[u][v] * sin(2 * pi * (u * i / rows + v * j / cols));
        }
      }
      printf("%f %f\n", real, imag);
    }
  }
}

int main() {
  int rows = 256;
  int cols = 256;
  int **img = (int **)malloc(rows * sizeof(int *));
  for (int i = 0; i < rows; i++) {
    img[i] = (int *)malloc(cols * sizeof(int));
  }

  // Initialize image
  for (int i = 0; i < rows; i++) {
    for (int j = 0; j < cols; j++) {
      img[i][j] = rand() % 256;
    }
  }

  fourierTransform(img, rows, cols);

  return 0;
}
